func Test_EdgeTranscribeEmptyAudio(t *testing.T) {
	// Transcription of a silent or empty audio file returns empty text
	var request pkg.CreateTranscriptionRequest
	if err := json.Unmarshal([]byte(`{"file":"silence.mp3","model":"whisper-1"}`), &request); err != nil {
		t.Fatalf("config parse failed: %v", err)
	}
	mockURL := os.Getenv("MOCK_SERVER_URL") + "/fixtures/edge_transcribe_empty_audio"
	client, clientErr := pkg.CreateClient("test-key", &mockURL, nil, nil, nil)
	if clientErr != nil {
		t.Fatalf("create client failed: %v", clientErr)
	}
	result, err := client.Transcribe(request)
	if err != nil {
		t.Fatalf("call failed: %v", err)
	}
	if !strings.Contains(string(result.Text), ``) {
		t.Errorf("expected to contain %s, got %v", ``, result.Text)
	}
}

